INSERT INTO public.event_testimonies (event_id, user_id, author_name, quote) VALUES ('df85910e-82da-4ef7-98d2-d4c827d1d0ec', '89241326-04f2-445f-b707-3b1d0e04b80e', 'Nathan Chaur', '« Avoir des explications de ci, de ça, pourquoi c''est là... c''est hyper intéressant et c''est un truc que moi je n''ai pas du tout, mais que je trouve hyper intéressant à connaître. »') ON CONFLICT (event_id, user_id) DO UPDATE SET quote=EXCLUDED.quote, updated_at=now();